import numpy as np

class DBSCAN:
    def __init__(self, eps: float = 0.5, min_samples: int = 5):
        self.eps = eps
        self.min_samples = min_samples
        self.labels_ = None

    def fit_predict(self, X: np.ndarray) -> np.ndarray:
        N = len(X)
        # Precompute pairwise distances
        dists = np.sqrt(np.sum((X[:, None, :] - X[None, :, :]) ** 2, axis=2))
        neighbors = [np.where(dists[i] <= self.eps)[0] for i in range(N)]

        labels = np.full(N, -1, dtype=int)
        cluster_id = 0
        visited = np.zeros(N, dtype=bool)

        for i in range(N):
            if visited[i]:
                continue
            visited[i] = True
            if len(neighbors[i]) < self.min_samples:
                labels[i] = -1  # noise
                continue

            # Start new cluster
            labels[i] = cluster_id
            queue = list(neighbors[i])
            qi = 0
            while qi < len(queue):
                j = queue[qi]
                qi += 1
                if not visited[j]:
                    visited[j] = True
                    if len(neighbors[j]) >= self.min_samples:
                        for nb in neighbors[j]:
                            if nb not in queue:
                                queue.append(nb)
                if labels[j] == -1:
                    labels[j] = cluster_id

            cluster_id += 1

        self.labels_ = labels
        return labels
